mats.system.loader.prototype.init_navigation = function() {

    var SELF = this;

	if (window.History && window.History.Adapter){
		window.History.Adapter.bind(window, 'statechange', function(){
			if (MANUAL_CONTENT_UPDATE){
				MANUAL_CONTENT_UPDATE = false;

				return;
			}

			var State = window.History.getState();

			for (var i = 0; i < SELF.navigate_back_callbacks.length; i++) { // call callbacks
                SELF.navigate_back_callbacks[i].call(SELF, i);
            }

			mats.system_misc.update_content(State.url, State.data, {no_history: true});
		});
	}

	$(document).on('click','a, input.internal_link_button',function(e) {
		var link = $(this);


		if (link.hasClass('back_button')){
			var parts = window.location.pathname.split('/');

			if (parts.length > 3) {
				// go to top level list page
				window.location = parts.slice(0, 3).join('/');
			} else if (parts.length == 3) {
				// already at top level list page, go to dashboard
				window.location = '/b/dashboard';
			} else if (window.History && window.History.Adapter){
				window.History.back();
			} else {
				window.history.go(-1);
			}
		}

		if (link.hasClass('modal_subpage')){
			return false;
		}

		if ($(this).hasClass('add-on') && !BUILD_EDITABLE){
			e.preventDefault();
			e.stopImmediatePropagation();
			return false;
		}

		var url = $(this).attr('href');

		if (link.hasClass('code_studio')){
			window.location = url;
			return true;
		}

		/* disable dynamic updates for ctr+click and apple+click */
		if (e.metaKey || e.ctrlKey || (typeof(url) === 'undefined') || ($(this).attr('target') == '_blank') || $(this).hasClass('loader_overridden')){
			return true;
		}

		var url_details = mats.system_misc.parse_url(url);
		if (url_details.params.focus_widget_group){
			var focus_widget_group = $(this).closest('.page').find('.page_widget_group[data-widget_group_id="' + url_details.params.focus_widget_group + '"]');
			var widgets = focus_widget_group.find('.page_widget').filter(function(){ return $(this).closest('.page_widget_group').is(focus_widget_group); });

			if (focus_widget_group.data('persist_focus_record')){
				var storage = new mats.system_storage();

				var persisted_focus_record_ids = storage.get('persisted_focus_record_ids');
				if (!persisted_focus_record_ids){
					persisted_focus_record_ids = {};
				}

				persisted_focus_record_ids[url_details.params.focus_widget_group] = url_details.params.focus_record_id;

				storage.set('persisted_focus_record_ids', persisted_focus_record_ids);
			}

			if (widgets.length){
				if (widgets.offset().top < $('html, body').scrollTop()){
					widgets.scroll_to();
				}

				if (focus_widget_group.data('booking_record_options') && focus_widget_group.data('instance')){
					focus_widget_group.data('instance').ajax('collect_booking_record_options', {
						data: url_details.params,
						success: function(booking_record_options) {
							focus_widget_group.data('booking_record_options', booking_record_options);
						}
					});
				}

				widgets.each(function(){
					let widget_params = $(this).data('params') !== undefined ? $(this).data('params') : {};

					if(widget_params.settings !== undefined && $(this).closest('.page_widget_wrapper').hasClass('hidden') == true
					&& widget_params.settings.hide_empty !== undefined && widget_params.settings.hide_empty == 1){
						$(this).closest('.page_widget_wrapper').show();
						$(this).closest('.page_widget_wrapper').removeClass('hidden');
					}

					$(this).data('instance').reload({data: url_details.params, highlight:true});
				});
			}

			return false;
		}

		if (($(this).hasClass('record_link') || mats.system_misc.is_cs_record_link($(this))) && !$(this).closest('.modal').length){
			mats.system_misc.set_back_destination($(this).attr('href'));
		}

		if ($('form.page_widget_group.abandon_prompt.has_changes').length){
			return true;
		}

		var level = 4; // Content
		if ($(this).closest('.matssoft-navigation, #mobile-top-tabs').length ){ // Top tab
			level = 0;
		} else if ( $(this).closest('.mobile-pages').length ){ // Mobile page (must check before #mobile-menu due to nesting)
			level = 3;
		} else if ( $(this).closest('.matssoft-menu, #mobile-menu').length ) { // Sub tab
			level = 2;
		} else if ( $(this).closest('.matssoft-sub-menu').length ){ // Box menu
			level = 3;
		}

		// Close mobile nav if open
		$('#subnav-trigger.active').removeClass('active');

		var loader = mats.system_registry.instance.get('instances')['loader'];
		var url = loader.get_session_redirect(window.location.pathname, $(this).attr('href'), level, $(this).hasClass('no_history'));

		var is_same_deployment_link = true;
		if ($(this).attr('href').match(/^https?:\/\//)) {
			var system_address_check_regex = new RegExp('^' + SYSTEM_ADDRESS.replace(/[.?*+^$[\]\\(){}|-]/g, "\\$&"), 'i');

			if (!$(this).attr('href').match(system_address_check_regex)) {
				is_same_deployment_link = false;
			}
		}

		var dynamic_link_regex = new RegExp('\/(i\/[^\/]+\/p|w\\/webpage)\/(([0-9A-Za-z-])*?(\/)?)*');
		var interface_regex = /[iw]\/([\w_-]*)(?=\/)/;
		var popup_regex = new RegExp("^"+SYS_PATH + "popup\/([\w_-]*)");

		if (is_same_deployment_link
			&& window.location.pathname.match(dynamic_link_regex)
			&& $(this).attr('href').match(dynamic_link_regex)
			&& !$(this).is('.static_links')
			&& ((
				null !== window.location.pathname.match(interface_regex)
				&& null !== $(this).attr('href').match(interface_regex)
				&& window.location.pathname.match(interface_regex)[1] == $(this).attr('href').match(interface_regex)[1]) // destination and source pages shares the same interface
			) || (
				null !== popup_regex.exec($(this).attr('href'))
			)) {

			var maintain_position = url_details.params.maintain_position || null;

			if (maintain_position === null) {
				maintain_position = $(this).data('maintain_position') || null;
			}
			mats.system_misc.update_content(url, {}, {no_history: $(this).hasClass('no_history'), session_storage_key: $(this).attr('data-redirect_session_storage_key'), maintain_position: maintain_position});

			return false;

		} else {
			$(this).attr('href', url);
			if ((url != '#') && !$(this).hasClass('click_handler_assigned') && mats.system_test_studio.replaying_activity_instance){
				mats.system_test_studio.replaying_activity_instance.full_page_refresh_pending = true;
			}
		}
		return true;
	});

	$('#header_inner div.search input[type="text"]').preparePlaceholder();
	$('#header_inner div.search form').submit(mats.handle_placeholder_submit);

	// Back to top links
	if ($('.matssoft-footer-toplink').length){
		$('.matssoft-footer-toplink').topLink({
			min: 10,
			fadeSpeed: 500
		});

		$('.matssoft-footer-toplink button').click(function(e) {
			e.preventDefault();
			$(this).blur();

			$('html, body').stop().animate({
				scrollTop: 0
			}, 600);
		});
	}
};

